import React from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import Statscard from './components/Statscard';
import PatientTable from './components/PatientTable';
import './App.css';

function App() {
  return (
    <div className="app-shell">
      {/* 1. The Global Header */}
      <Navbar />

      <div className="main-wrapper">
        {/* 2. The Navigation Sidebar */}
        <Sidebar />

        {/* 3. The Dashboard Content Area */}
        <main className="content-area">
          <header className="dashboard-header">
            <h1>Hospital Administrator Dashboard</h1>
            <p>Reviewing real-time patient admissions and hospital capacity.</p>
          </header>

          {/* 4. The Metrics Row */}
          <div className="stats-grid">
            <StatsCard title="Total Patients" value="1,240" icon="👥" color="#3498db" trend="+12% this week" />
            <StatsCard title="Available Beds" value="42" icon="🛏️" color="#e67e22" trend="High Demand" />
            <Statscard title="Today's Appt." value="18" icon="📅" color="#9b59b6" trend="4 Pending" />
            <Statscard title="Total Revenue" value="$12,450" icon="💰" color="#2ecc71" trend="+5.4%" />
          </div>

          {/* 5. The Patient Data Table */}
          <PatientTable />
        </main>
      </div>
    </div>
  );
}

export default App;
